package common;

import com.google.gson.Gson;
import com.google.gson.JsonArray;
import com.google.gson.JsonPrimitive;

public class JsonSmokeTest {
    public static void main(String[] args) {
        Gson gson = new Gson();
        JsonArray datos = new JsonArray();
        datos.add(10);
        datos.add(5);

        Peticion peticion = new Peticion("SUMA", datos);
        String jsonPeticion = gson.toJson(peticion);
        System.out.println("Peticion JSON: " + jsonPeticion);

        Respuesta respuesta = Respuesta.ok(new JsonPrimitive(15.0));
        String jsonRespuesta = gson.toJson(respuesta);
        System.out.println("Respuesta JSON: " + jsonRespuesta);
    }
}

